import React, { useState } from "react";

function SubscriptionForm({ subscriptions, setSubscriptions }) {
  const [name, setName] = useState("");
  const [amount, setAmount] = useState("");
  const totalSubscription = subscriptions.reduce(
  (sum, sub) => sum + Number(sub.amount || 0),
  0
);

  const addSubscription = () => {
    const trimmedName = name.trim();
    const parsedAmount = parseFloat(amount);

    if (!trimmedName || isNaN(parsedAmount) || parsedAmount <= 0) {
      alert("Enter a valid subscription name and amount");
      return;
    }

    const newSub = {
      id: Date.now(),
      name: trimmedName,
      amount: parsedAmount,
    };

    setSubscriptions([...subscriptions, newSub]);

    setName("");
    setAmount("");
  };

  // DELETE FUNCTION
  const deleteSubscription = (id) => {
    const updated = subscriptions.filter((sub) => sub.id !== id);
    setSubscriptions(updated);
  };

  return (
    <div className="bg-white rounded-xl shadow p-6 mb-8">
      <h3 className="text-lg font-semibold mb-4">Add Subscription</h3>

      <div className="grid grid-cols-3 gap-3">
        <input
          type="text"
          placeholder="Subscription Name"
          className="border p-2 rounded"
          value={name}
          onChange={(e) => setName(e.target.value)}
        />

        <input
          type="number"
          placeholder="Amount"
          className="border p-2 rounded"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
        />

        <button
          className="bg-green-500 text-white px-4 py-2 rounded"
          onClick={addSubscription}
        >
          Add
        </button>
      </div>

      {subscriptions.length > 0 && (
        <ul className="mt-4 space-y-2">
          {subscriptions.map((sub) => (
            <li
              key={sub.id}
              className="flex justify-between items-center bg-gray-100 p-2 rounded"
            >
              <span>{sub.name}</span>

              <div className="flex items-center gap-3">
                <span>₹{Number(sub.amount || 0).toFixed(2)}</span>

                <button
                  className="bg-red-500 text-white px-2 py-1 rounded"
                  onClick={() => deleteSubscription(sub.id)}
                >
                  Delete
                </button>
              </div>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default SubscriptionForm;
